INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Ht7Kp2Lm9N', 'zh-hant', '暴龍大道', 0, '以最大的肉食恐龍命名，霸王龍身長可達40英尺。', 0, '香港旺角', 0, '{"neighbourhood":"旺角","administrativeAreaLevel1":"九龍","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Ht7Kp2Lm9N', 'zh-hans', '暴龙大道', 0, '以最大的肉食恐龙命名，霸王龙身长可达40英尺。', 0, '香港旺角', 0, '{"neighbourhood":"旺角","administrativeAreaLevel1":"九龙","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Np9Lm2Kt7H', 'zh-hant', '迅猛龍巷', 0, '迅猛龍實際上比電影中描繪的要小得多，只有火雞大小。', 0, '香港中環', 0, '{"neighbourhood":"中環","administrativeAreaLevel1":"香港島","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Np9Lm2Kt7H', 'zh-hans', '迅猛龙巷', 0, '迅猛龙实际上比电影中描绘的要小得多，只有火鸡大小。', 0, '香港中环', 0, '{"neighbourhood":"中环","administrativeAreaLevel1":"香港岛","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Lm7Ht2Np9K', 'zh-hant', '劍龍街', 0, '劍龍的大腦大小如核桃，是所有恐龍中腦容量與體型比例最小的之一。', 0, '香港油麻地', 0, '{"neighbourhood":"油麻地","administrativeAreaLevel1":"九龍","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Lm7Ht2Np9K', 'zh-hans', '剑龙街', 0, '剑龙的大脑大小如核桃，是所有恐龙中脑容量与体型比例最小的之一。', 0, '香港油麻地', 0, '{"neighbourhood":"油麻地","administrativeAreaLevel1":"九龙","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Kt9Np2Lm7H', 'zh-hant', '翼龍徑', 0, '與普遍認知相反，翼龍並不是恐龍，而是飛行爬行動物。', 0, '香港土瓜灣', 0, '{"neighbourhood":"土瓜灣","administrativeAreaLevel1":"九龍","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Kt9Np2Lm7H', 'zh-hans', '翼龙径', 0, '与普遍认知相反，翼龙并不是恐龙，而是飞行爬行动物。', 0, '香港土瓜湾', 0, '{"neighbourhood":"土瓜湾","administrativeAreaLevel1":"九龙","country":"香港"}');
INSERT INTO featureI18n (featureId, lang, title, titleGen, description, descriptionGen, displayAddress, displayAddressGen, addressProperties) VALUES ('Ht2Lm7Np9K', 'zh-hant', '腕龍大道', 0, '腕龍可以長到39英尺高，是已知最高的恐龍之一。', 0, '香港九龍城', 0, '{"neighbourhood":"九龍城","administrativeAreaLevel1":"九龍","country":"香港"}');
