INSERT INTO organisation (id, code, name, nameGen, nameShort, nameShortGen, description, descriptionGen, url, imageId, isPublished, isArchived, publishedAt, publisherId, createdAt, modifiedAt) VALUES ('oZTVNE4brR7m', 'hkdl', 'Hong Kong Data Layer', 0, 'HKDL', 0, 'A Useful, Beautiful Hong Kong', 0, 'https://hype.hk', 'gwKxauY8pWeJ', 0, 0, '2024-11-25T17:48:56.888Z', 'p6WnJ-DKl0c1', '2024-11-25T17:48:56.888Z', '2024-12-09T18:08:59.996Z');
INSERT INTO organisationI18n (organisationId, lang, name, nameGen, nameShort, nameShortGen, description, descriptionGen) VALUES ('iLszdNS3w208', 'zh-hans', '香港街道名称', 1, '香港街道名称', 1, '作为一名跨学科研究员和设计师，Diana Pang 创造了沉浸式体验，探索系统、城市环境和康复途径的交汇点。通过融合物理和数字元素，她创作了令人回味的故事，激励人们重新想象他们与世界的关系。', 1);
INSERT INTO organisationI18n (organisationId, lang, name, nameGen, nameShort, nameShortGen, description, descriptionGen) VALUES ('iLszdNS3w208', 'zh-hant', '香港街名稱', 1, '香港街名稱', 1, '身為多學科研究員和設計師，Diana Pang 創造了沉浸式體驗，探索系統、城市環境和療癒途徑的交叉點。透過融合物理和數位元素，她精心製作了令人回味的敘事，激發人們重新想像他們與世界的關係。', 1);
INSERT INTO organisationI18n (organisationId, lang, name, nameGen, nameShort, nameShortGen, description, descriptionGen) VALUES ('oZTVNE4brR7m', 'zh-hans', '香港数据层', 1, 'HKDL', 1, '一个有用、美丽的香港', 1);
