INSERT INTO organisationI18n (organisationId, lang, name, nameGen, nameShort, nameShortGen, description, descriptionGen) VALUES ('4Jsk5LngvFZq', 'zh-hant', '幽靈貼圖', 0, '幽靈貼圖', 0, '召喚我哋城市過去嘅人物。 記錄香港城市景觀嘅已失效和褪色迹象。', 1);
INSERT INTO organisationI18n (organisationId, lang, name, nameGen, nameShort, nameShortGen, description, descriptionGen) VALUES ('4Jsk5LngvFZq', 'zh-hans', '幽灵贴图', 1, '幽灵贴图', 1, '召唤我们城市过去的人物。记录香港城市景观的已失效和褪色迹象。', 1);
